<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Maze Discovery Bots</title>
<style>
  :root { color-scheme: dark; }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    background: #10151c;
    color: #e8edf3;
    font-family: Arial, sans-serif;
  }
  h1 { margin: 16px 0 8px; font-size: 24px; }
  .info {
    display: flex;
    gap: 24px;
    align-items: center;
    margin-bottom: 10px;
    font-size: 16px;
  }
  .info strong { color: #70d6ff; }
  button {
    border: 0;
    border-radius: 5px;
    padding: 8px 15px;
    background: #2676c9;
    color: white;
    cursor: pointer;
    font-weight: bold;
  }
  button:hover { background: #348ce4; }
  #maze {
    width: min(92vw, 680px);
    height: min(92vw, 680px);
    min-width: 400px;
    min-height: 400px;
    max-width: 680px;
    max-height: 680px;
    background: #17202b;
    border: 2px solid #526273;
    display: block;
  }
  .hint { margin-top: 8px; color: #9eabb9; font-size: 12px; }
</style>
</head>
<body>
<h1>Maze Discovery</h1>
<div class="info">
  <span>Completed: <strong id="completed">0 / 24</strong></span>
  <span>Timer: <strong id="timer">0</strong></span>
  <button id="reset">Reset</button>
</div>
<canvas id="maze" width="680" height="680"></canvas>
<div class="hint">Each bot independently explores and backtracks without knowing the maze.</div>

<script>
(() => {
  "use strict";

  const canvas = document.getElementById("maze");
  const ctx = canvas.getContext("2d");
  const completedEl = document.getElementById("completed");
  const timerEl = document.getElementById("timer");
  const resetBtn = document.getElementById("reset");

  const ROWS = 21, COLS = 21, BOT_COUNT = 24;
  const DIRS = [
    { dr: -1, dc: 0, wall: "n", opposite: "s" },
    { dr: 0, dc: 1, wall: "e", opposite: "w" },
    { dr: 1, dc: 0, wall: "s", opposite: "n" },
    { dr: 0, dc: -1, wall: "w", opposite: "e" }
  ];
  const COLORS = [
    "#ff595e","#ff924c","#ffca3a","#8ac926","#52b788","#00b4d8",
    "#1982c4","#4267ac","#6a4c93","#b565a7","#f72585","#e76f51",
    "#2a9d8f","#90be6d","#f9c74f","#577590","#c77dff","#4cc9f0",
    "#ef476f","#06d6a0","#ffd166","#118ab2","#8338ec","#fb5607"
  ];

  let maze, spawn, exitCell, seedValue, tickCount, elapsed, bots;
  let animationFrame = 0;

  function PRNG(seed) {
    let x = (seed >>> 0) || 0x9e3779b9;
    return function() {
      x ^= x << 13; x >>>= 0;
      x ^= x >>> 17; x >>>= 0;
      x ^= x << 5; x >>>= 0;
      return (x >>> 0) / 4294967296;
    };
  }

  function makeMaze(seed) {
    const rand = PRNG(seed);
    const cells = [];
    for (let r = 0; r < ROWS; r++) {
      cells[r] = [];
      for (let c = 0; c < COLS; c++) {
        cells[r][c] = {
          n: true, e: true, s: true, w: true, visited: false
        };
      }
    }

    const stack = [{r: 0, c: 0}];
    cells[0][0].visited = true;
    while (stack.length) {
      const cur = stack[stack.length - 1];
      const choices = [];
      for (const d of DIRS) {
        const nr = cur.r + d.dr, nc = cur.c + d.dc;
        if (nr >= 0 && nr < ROWS && nc >= 0 && nc < COLS &&
            !cells[nr][nc].visited) {
          choices.push({d, nr, nc});
        }
      }
      if (!choices.length) {
        stack.pop();
        continue;
      }
      const choice = choices[Math.floor(rand() * choices.length)];
      const a = cells[cur.r][cur.c], b = cells[choice.nr][choice.nc];
      a[choice.d.wall] = false;
      b[choice.d.opposite] = false;
      b.visited = true;
      stack.push({r: choice.nr, c: choice.nc});
    }

    for (const row of cells) for (const cell of row) delete cell.visited;
    return cells;
  }

  function shuffledOrder(rand) {
    const a = [0, 1, 2, 3];
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(rand() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  }

  function makeBot(index, rand) {
    const start = {r: spawn.r, c: spawn.c};
    return {
      id: index + 1,
      color: COLORS[index % COLORS.length],
      path: [start],
      deadEnds: [],
      finishTick: null,

      _r: start.r,
      _c: start.c,
      _stack: [start],
      _edgeVisits: Object.create(null),
      _deadSet: new Set(),
      _order: shuffledOrder(rand),
      _from: {r: start.r, c: start.c},
      _to: {r: start.r, c: start.c},
      _animAt: performance.now()
    };
  }

  function edgeKey(r1, c1, r2, c2) {
    if (r1 < r2 || (r1 === r2 && c1 < c2))
      return r1 + "," + c1 + "|" + r2 + "," + c2;
    return r2 + "," + c2 + "|" + r1 + "," + c1;
  }

  function markDead(bot, r, c) {
    const key = r + "," + c;
    if (!bot._deadSet.has(key)) {
      bot._deadSet.add(key);
      bot.deadEnds.push({r, c});
    }
  }

  function moveBot(bot, nr, nc, forward) {
    const old = {r: bot._r, c: bot._c};
    bot._from = old;
    bot._to = {r: nr, c: nc};
    bot._animAt = performance.now();
    bot._r = nr;
    bot._c = nc;
    bot.path.push({r: nr, c: nc});

    const key = edgeKey(old.r, old.c, nr, nc);
    bot._edgeVisits[key] = (bot._edgeVisits[key] || 0) + 1;
    if (forward) bot._stack.push({r: nr, c: nc});
    else bot._stack.pop();
  }

  function stepBot(bot) {
    if (bot.finishTick !== null) return;

    // Arrival is the only way a bot learns that a cell is the exit.
    if (bot._r === exitCell.r && bot._c === exitCell.c) {
      bot.finishTick = tickCount;
      return;
    }

    const available = [];
    for (const di of bot._order) {
      const d = DIRS[di];
      const nr = bot._r + d.dr, nc = bot._c + d.dc;
      if (nr < 0 || nr >= ROWS || nc < 0 || nc >= COLS) continue;
      if (maze[bot._r][bot._c][d.wall]) continue;

      const key = edgeKey(bot._r, bot._c, nr, nc);
      const used = bot._edgeVisits[key] || 0;
      // A passage is never used more than once in either direction.
      if (used === 0) available.push({nr, nc});
    }

    if (available.length) {
      const next = available[0];
      moveBot(bot, next.nr, next.nc, true);
      if (bot._r === exitCell.r && bot._c === exitCell.c)
        bot.finishTick = tickCount;
    } else if (bot._stack.length > 1) {
      markDead(bot, bot._r, bot._c);
      const parent = bot._stack[bot._stack.length - 2];
      moveBot(bot, parent.r, parent.c, false);
    } else {
      // This can only occur after the entire connected maze was searched.
      markDead(bot, bot._r, bot._c);
    }
  }

  function allFinished() {
    return bots.every(b => b.finishTick !== null);
  }

  function updateUI() {
    const count = bots.filter(b => b.finishTick !== null).length;
    completedEl.textContent = count + " / " + BOT_COUNT;
    timerEl.textContent = String(elapsed);
  }

  function draw() {
    const w = canvas.width, h = canvas.height;
    const cw = w / COLS, ch = h / ROWS;
    ctx.clearRect(0, 0, w, h);
    ctx.fillStyle = "#17202b";
    ctx.fillRect(0, 0, w, h);

    // Subtle cell grid.
    ctx.strokeStyle = "rgba(115,140,165,.12)";
    ctx.lineWidth = 1;
    for (let r = 0; r <= ROWS; r++) {
      ctx.beginPath(); ctx.moveTo(0, r * ch); ctx.lineTo(w, r * ch); ctx.stroke();
    }
    for (let c = 0; c <= COLS; c++) {
      ctx.beginPath(); ctx.moveTo(c * cw, 0); ctx.lineTo(c * cw, h); ctx.stroke();
    }

    // Exit and spawn markers.
    ctx.fillStyle = "#35e06f";
    ctx.fillRect(exitCell.c * cw + cw * .25, exitCell.r * ch + ch * .25,
                 cw * .5, ch * .5);
    ctx.fillStyle = "#ffffff";
    ctx.globalAlpha = .8;
    ctx.fillRect(spawn.c * cw + cw * .35, spawn.r * ch + ch * .35,
                 cw * .3, ch * .3);
    ctx.globalAlpha = 1;

    // Walls.
    ctx.strokeStyle = "#d9e4ef";
    ctx.lineWidth = Math.max(2, Math.min(cw, ch) * .11);
    ctx.lineCap = "square";
    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS; c++) {
        const x = c * cw, y = r * ch, cell = maze[r][c];
        if (cell.n) { ctx.beginPath(); ctx.moveTo(x,y); ctx.lineTo(x+cw,y); ctx.stroke(); }
        if (cell.e) { ctx.beginPath(); ctx.moveTo(x+cw,y); ctx.lineTo(x+cw,y+ch); ctx.stroke(); }
        if (cell.s) { ctx.beginPath(); ctx.moveTo(x,y+ch); ctx.lineTo(x+cw,y+ch); ctx.stroke(); }
        if (cell.w) { ctx.beginPath(); ctx.moveTo(x,y); ctx.lineTo(x,y+ch); ctx.stroke(); }
      }
    }

    const now = performance.now();
    const duration = 145;
    for (const b of bots) {
      let t = Math.min(1, (now - b._animAt) / duration);
      const rr = b._from.r + (b._to.r - b._from.r) * t;
      const cc = b._from.c + (b._to.c - b._from.c) * t;
      const x = (cc + .5) * cw, y = (rr + .5) * ch;
      const radius = Math.max(3, Math.min(cw, ch) * .27);

      ctx.beginPath();
      ctx.arc(x, y, radius + 1.8, 0, Math.PI * 2);
      ctx.fillStyle = "#10151c";
      ctx.fill();

      ctx.beginPath();
      ctx.arc(x, y, radius, 0, Math.PI * 2);
      ctx.fillStyle = b.color;
      ctx.fill();
      ctx.strokeStyle = "#ffffff";
      ctx.lineWidth = 1;
      ctx.stroke();
    }
    animationFrame = requestAnimationFrame(draw);
  }

  function reset(seed) {
    seedValue = (typeof seed === "number" && Number.isFinite(seed))
      ? (seed >>> 0)
      : ((Date.now() ^ Math.floor(Math.random() * 0xffffffff)) >>> 0);

    const rand = PRNG(seedValue);
    maze = makeMaze(seedValue);

    spawn = {r: Math.floor(ROWS / 2), c: Math.floor(COLS / 2)};
    do {
      exitCell = {r: Math.floor(rand() * ROWS), c: Math.floor(rand() * COLS)};
    } while (exitCell.r === spawn.r && exitCell.c === spawn.c);

    bots = [];
    for (let i = 0; i < BOT_COUNT; i++)
      bots.push(makeBot(i, rand));

    tickCount = 0;
    elapsed = 0;
    updateUI();
    draw();
  }

  const game = {
    tick(n) {
      n = Math.max(0, Math.floor(Number(n) || 0));
      for (let i = 0; i < n; i++) {
        if (allFinished()) break;
        tickCount++;
        for (const bot of bots) stepBot(bot);
        // Freeze exactly on the tick of the last arrival.
        elapsed = tickCount;
        updateUI();
        if (allFinished()) break;
      }
      draw();
    },
    reset,
    get elapsed() { return elapsed; },
    get size() { return {rows: ROWS, cols: COLS}; },
    get spawn() { return {r: spawn.r, c: spawn.c}; },
    get exit() { return {r: exitCell.r, c: exitCell.c}; },
    walls(r, c) {
      if (r < 0 || r >= ROWS || c < 0 || c >= COLS) return null;
      const x = maze[r][c];
      return {n: !!x.n, e: !!x.e, s: !!x.s, w: !!x.w};
    },
    get bots() { return bots; }
  };

  window.game = game;
  reset(123456789);
  resetBtn.addEventListener("click", () => reset());
})();
</script>
</body>
</html>
